export * from './step-content.directive';
export * from './step.component';
export * from './stepper.component';
export * from './stepper.token';
export * from './stepper.variants';
export * from './stepper.imports';

import { Directive } from '@angular/core';

@Directive({
  selector: 'ng-template[hbStepContent]',
})
export class HbStepContentDirective {}

import { NgTemplateOutlet } from '@angular/common';
import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChild,
  inject,
  input,
  TemplateRef,
  ViewEncapsulation,
} from '@angular/core';
import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorCheck } from '@ng-icons/phosphor-icons/regular';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbStepContentDirective } from './step-content.directive';
import { HB_STEPPER, type HbStepRef, type HbStepValue } from './stepper.token';
import { connectorVariants, stepMarkerVariants } from './stepper.variants';

@Component({
  selector: 'hb-step',
  imports: [NgIcon, NgTemplateOutlet],
  viewProviders: [provideIcons({ phosphorCheck })],
  template: `
    @if (orientation() === 'horizontal') {
      <button
        type="button"
        class="flex items-center gap-2.5 text-left disabled:cursor-default"
        data-slot="step-trigger"
        [disabled]="!clickable()"
        [attr.aria-current]="isActive() ? 'step' : null"
        (click)="onActivate()"
      >
        <ng-container [ngTemplateOutlet]="marker" />
        <ng-container [ngTemplateOutlet]="labels" />
      </button>
      @if (!isLast()) {
        <span [class]="connectorClasses()" data-slot="step-connector" class="mx-2.5"></span>
      }
    } @else {
      <div class="flex flex-col items-center self-stretch">
        <button
          type="button"
          class="rounded-full disabled:cursor-default"
          data-slot="step-trigger"
          [disabled]="!clickable()"
          [attr.aria-current]="isActive() ? 'step' : null"
          (click)="onActivate()"
        >
          <ng-container [ngTemplateOutlet]="marker" />
        </button>
        @if (!isLast()) {
          <span [class]="connectorClasses()" data-slot="step-connector" class="my-1.5"></span>
        }
      </div>
      <div class="flex flex-1 flex-col pb-6">
        <button
          type="button"
          class="text-left disabled:cursor-default"
          [disabled]="!clickable()"
          (click)="onActivate()"
        >
          <ng-container [ngTemplateOutlet]="labels" />
        </button>
        @if (isActive() && contentTemplate(); as tpl) {
          <div class="pt-2" data-slot="step-content">
            <ng-container
              [ngTemplateOutlet]="tpl"
              [ngTemplateOutletContext]="{ $implicit: stepper.contextFor(index()) }"
            />
          </div>
        }
      </div>
    }

    <ng-template #marker>
      <span [class]="markerClasses()" data-slot="step-marker" [attr.data-state]="state()">
        @if (state() === 'completed') {
          <ng-icon name="phosphorCheck" />
        } @else if (hbIcon(); as icon) {
          <ng-icon [name]="icon" />
        } @else {
          {{ index() + 1 }}
        }
      </span>
    </ng-template>

    <ng-template #labels>
      <span class="flex min-w-0 flex-col">
        <span
          class="truncate text-sm font-medium"
          [class.text-foreground]="isActive() || state() === 'completed'"
          [class.text-muted-foreground]="state() === 'inactive'"
          >{{ hbTitle() }}</span
        >
        @if (hbDescription()) {
          <span class="truncate text-xs text-muted-foreground">{{ hbDescription() }}</span>
        }
      </span>
    </ng-template>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'hostClasses()',
    '[attr.data-slot]': "'step'",
    '[attr.data-state]': 'state()',
  },
  exportAs: 'hbStep',
})
export class HbStepComponent implements HbStepRef {
  protected readonly stepper = inject(HB_STEPPER);

  readonly hbValue = input<HbStepValue | undefined>(undefined);
  readonly hbTitle = input('');
  readonly hbDescription = input('');
  readonly hbIcon = input<string>();
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');

  readonly contentTemplate = contentChild(HbStepContentDirective, { read: TemplateRef });

  readonly index = computed<number>(() => this.stepper.indexOf(this));
  readonly value = computed<HbStepValue>(() => this.hbValue() ?? this.index() + 1);
  readonly disabled = this.hbDisabled;

  protected readonly orientation = this.stepper.orientation;
  protected readonly isActive = computed(() => this.value() === this.stepper.active());
  protected readonly state = computed<'inactive' | 'active' | 'completed'>(() => {
    if (this.isActive()) return 'active';
    if (this.stepper.isCompleted(this.index())) return 'completed';
    return 'inactive';
  });
  protected readonly isLast = computed(() => this.index() === this.stepper.steps().length - 1);
  protected readonly clickable = computed(
    () => !this.hbDisabled() && this.stepper.canActivate(this.index()),
  );

  protected readonly hostClasses = computed(() => {
    if (this.orientation() === 'horizontal') {
      return cn('flex items-center', !this.isLast() && 'flex-1', this.class());
    }
    return cn('flex gap-3', this.class());
  });
  protected readonly markerClasses = computed(() => stepMarkerVariants({ state: this.state() }));
  protected readonly connectorClasses = computed(() =>
    connectorVariants({
      orientation: this.orientation(),
      completed: this.stepper.isCompleted(this.index()),
    }),
  );

  protected onActivate(): void {
    if (this.clickable()) this.stepper.activate(this.value());
  }
}

import { NgTemplateOutlet } from '@angular/common';
import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChildren,
  forwardRef,
  input,
  model,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbStepComponent } from './step.component';
import {
  HB_STEPPER,
  type HbStepContext,
  type HbStepperContext,
  type HbStepperOrientation,
  type HbStepValue,
} from './stepper.token';
import { stepListClass, stepperClass } from './stepper.variants';

@Component({
  selector: 'hb-stepper',
  imports: [NgTemplateOutlet],
  providers: [{ provide: HB_STEPPER, useExisting: forwardRef(() => HbStepperComponent) }],
  template: `
    <div
      [class]="listClasses()"
      data-slot="stepper-list"
      role="tablist"
      [attr.aria-orientation]="hbOrientation()"
    >
      <ng-content />
    </div>

    @if (hbOrientation() === 'horizontal' && activeTemplate(); as tpl) {
      <div class="mt-4 w-full" data-slot="stepper-content">
        <ng-container
          [ngTemplateOutlet]="tpl"
          [ngTemplateOutletContext]="{ $implicit: contextFor(activeIndex()) }"
        />
      </div>
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'stepper'",
    '[attr.data-orientation]': 'hbOrientation()',
  },
  exportAs: 'hbStepper',
})
export class HbStepperComponent implements HbStepperContext {
  readonly hbValue = model<HbStepValue>(1);
  readonly hbOrientation = input<HbStepperOrientation>('horizontal');
  readonly hbLinear = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');

  private readonly stepQuery = contentChildren(HbStepComponent);

  readonly orientation = this.hbOrientation;
  readonly linear = this.hbLinear;
  readonly active = this.hbValue.asReadonly();
  readonly steps = this.stepQuery;

  readonly activeIndex = computed(() => {
    const i = this.stepQuery().findIndex((s) => s.value() === this.hbValue());
    return i === -1 ? 0 : i;
  });
  readonly isFirst = computed(() => this.activeIndex() <= 0);
  readonly isLast = computed(() => this.activeIndex() >= this.stepQuery().length - 1);

  protected readonly classes = computed(() => cn(stepperClass, 'flex-col', this.class()));
  protected readonly listClasses = computed(() =>
    cn(stepListClass, this.hbOrientation() === 'horizontal' ? 'w-full items-center' : 'flex-col'),
  );
  protected readonly activeTemplate = computed(
    () => this.stepQuery()[this.activeIndex()]?.contentTemplate() ?? null,
  );

  indexOf(step: HbStepComponent): number {
    return this.stepQuery().indexOf(step);
  }
  isCompleted(index: number): boolean {
    return index < this.activeIndex();
  }
  canActivate(index: number): boolean {
    return !this.hbLinear() || index <= this.activeIndex();
  }
  activate(value: HbStepValue): void {
    this.hbValue.set(value);
  }
  next(): void {
    const arr = this.stepQuery();
    const i = this.activeIndex();
    if (i < arr.length - 1) this.hbValue.set(arr[i + 1].value());
  }
  prev(): void {
    const arr = this.stepQuery();
    const i = this.activeIndex();
    if (i > 0) this.hbValue.set(arr[i - 1].value());
  }
  contextFor(index: number): HbStepContext {
    return {
      active: this.hbValue(),
      index,
      isFirst: index === 0,
      isLast: index === this.stepQuery().length - 1,
      next: () => this.next(),
      prev: () => this.prev(),
      activate: (value: HbStepValue) => this.activate(value),
    };
  }
}

import { HbStepContentDirective } from './step-content.directive';
import { HbStepComponent } from './step.component';
import { HbStepperComponent } from './stepper.component';

export const HbStepperImports = [
  HbStepperComponent,
  HbStepComponent,
  HbStepContentDirective,
] as const;

import { InjectionToken, type Signal } from '@angular/core';

export type HbStepperOrientation = 'horizontal' | 'vertical';
export type HbStepValue = number | string;

export interface HbStepContext {
  readonly active: HbStepValue;
  readonly index: number;
  readonly isFirst: boolean;
  readonly isLast: boolean;
  next(): void;
  prev(): void;
  activate(value: HbStepValue): void;
}

export interface HbStepRef {
  readonly value: Signal<HbStepValue>;
  readonly disabled: Signal<boolean>;
}

export interface HbStepperContext {
  readonly orientation: Signal<HbStepperOrientation>;
  readonly linear: Signal<boolean>;
  readonly active: Signal<HbStepValue>;
  readonly activeIndex: Signal<number>;
  readonly steps: Signal<readonly HbStepRef[]>;
  indexOf(step: unknown): number;
  isCompleted(index: number): boolean;
  canActivate(index: number): boolean;
  activate(value: HbStepValue): void;
  next(): void;
  prev(): void;
  contextFor(index: number): HbStepContext;
}

export const HB_STEPPER = new InjectionToken<HbStepperContext>('HB_STEPPER');

import { cva, type VariantProps } from 'class-variance-authority';

export const stepperClass = 'flex w-full';

export const stepListClass = 'flex';

export const stepMarkerVariants = cva(
  'flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium transition-colors',
  {
    variants: {
      state: {
        inactive: 'border-border bg-background text-muted-foreground',
        active: 'border-primary bg-primary text-primary-foreground',
        completed: 'border-primary bg-primary text-primary-foreground',
      },
    },
    defaultVariants: { state: 'inactive' },
  },
);

export const connectorVariants = cva('shrink-0 rounded-full bg-border transition-colors', {
  variants: {
    orientation: {
      horizontal: 'h-0.5 flex-1',
      vertical: 'w-0.5 flex-1',
    },
    completed: {
      true: 'bg-primary',
      false: '',
    },
  },
  defaultVariants: { orientation: 'horizontal', completed: false },
});

export type HbStepMarkerVariants = VariantProps<typeof stepMarkerVariants>;
export type HbConnectorVariants = VariantProps<typeof connectorVariants>;

